<div class="table-wrap"><table class="leads-table"><thead><tr><th>Empresa</th><th>Contacto</th><th>Segmento</th><th>Puntaje</th><th>Riesgo</th><th>Estado</th><th>Responsable</th><th>Ingreso</th><th></th></tr></thead><tbody><?php foreach($leads as $l): ?><tr><td><strong><?=e($l['company_name'])?></strong><small><?=e($l['company_rut'])?></small></td><td><?=e($l['contact_name'])?><small><?=e($l['email'])?></small><small><?=e($l['phone'] ?? '')?></small></td><td><?=e($l['industry'])?><small><?=e($l['city'] ?? '')?><?=!empty($l['workers_count'])?' · '.e($l['workers_count']).' trab.':''?></small></td><td><span class="score-chip"><?=e($l['risk_score'])?>%</span></td><td><span class="badge risk <?=str_contains((string)$l['risk_level'],'bajo')?'low':(str_contains((string)$l['risk_level'],'medio')?'mid':'high')?>"><?=e($l['risk_level'])?></span></td><td><span class="badge status"><?=e($l['risk_status'])?></span></td><td><?=e($l['assigned_name']??'Sin asignar')?></td><td><small><?=!empty($l['created_at'])?date('d/m/Y', strtotime($l['created_at'])):''?></small></td><td><a class="btn ghost compact" href="<?=url('/leads/'.$l['id'])?>">Ver</a></td></tr><?php endforeach; if(empty($leads)): ?><tr><td colspan="9"><p class="empty">No se encontraron leads con los filtros seleccionados.</p></td></tr><?php endif; ?></tbody></table></div>
